buggyCode:
function FormInput(props) {
  const { className, ...rest } = props
  return (
    <input
      className={className}
      {...rest}
    />
  )
}

solutionCode:
import React from 'react'

const FormInput = React.forwardRef(function FormInput(props, ref) {
  const { className, ...rest } = props
  return (
    <input
      ref={ref}
      className={className}
      {...rest}
    />
  )
})

export default FormInput

